ompany_name" required></label><label class="field"><span>Yetkili</span><input name="contact_name"></label><label class="field"><span>Telefon</span><input name="phone"></label><label class="field"><span>E-posta</span><input name="email" type="email"></label><label class="field"><span>Vergi no</span><input name="tax_number"></label><label class="field"><span>Adres</span><textarea name="address"></textarea></label><button class="button button--block" type="submit">Kaydet</button></form></section></aside><?php endif; ?></div><?= $this->endSection() ?>
